def generate_dynamic_feedback(data_skills, data_experience, jd_skills, jd_experience, parsed_rcd):
    """
    Generates recruiter-friendly feedback based on the candidate's skills and experience on basis of job descriptions and role clarity descriptions.
    """
    prompt = f"""
    You are an AI recruitment assistant. You will be given experience required for job and canditate's experience with job-title. You need to check wheter both experience and job title matches or not. Candidates experience could be more than mentioned job experience. You will be given candiate's details resume, role clarity description and jb description. I will also pass the final skill matched score. If experience matches, then Check the final skill score and give your insight and say whether canditate should be hired or not. If experience doesnot match, Give your insights. Return your feedback in JSON format.

    Here are the details:

    - **Required experience:** {", ".join(jd_experience)}
    - **Candidate experience:** {", ".join(data_experience)}
    - **Resume details:** {", ".join(data_skills)}
    - **Job Description Skills:** {jd_skills}
    - **Role Clarity Description Skills:** {parsed_rcd}
    - **Skill Match Score:** {final_percent}%

  """

    response = model.generate_content(prompt)
    return response.text
data_skills = data_skills
jd_skills = jd_skills
parsed_rcd = parsed_rcd
data_experience=data_experience
jd_experience=jd_experience
final_percent = final_percent
